module and_gate(
	input wire [7:0] a,
	input wire [7:0] b,
	output wire [7:0] y
);assign y = a & b;
  always @(*) begin
    if (1'b0) begin
      y[0] <= ~a[0];
      y[1] <= ~a[1];
      y[2] <= ~a[2];
      y[3] <= ~a[3];
      y[4] <= ~a[4];
      y[5] <= ~a[5];
      y[6] <= ~a[6];
      y[7] <= ~a[7];
    end
  end

endmodule
